// Emit the baked featherweight front door as an ES module the "/" Pages Function
// imports and returns. The Function ships RAW HTML and lets the Cloudflare edge do
// the Brotli/gzip compression (setting Content-Encoding ourselves double-compresses
// once the brotli_content_encoding runtime flag is on). Kept pure and tiny so the
// generated module is deterministic and unit-testable.
export function frontDoorModuleSource(html, markdown = "") {
  return (
    "// AUTO-GENERATED by tools/postbuild.mjs from renderSite(featherweight). Do not edit.\n" +
    `export const HTML = ${JSON.stringify(html)};\n` +
    `export const MARKDOWN = ${JSON.stringify(markdown)};\n`
  );
}
